mapper.update:
UPDATE event
SET name = #{name}, location = #{location}, event_date = #{eventDate},
    reg_start_time = #{regStartTime}, reg_end_time = #{regEndTime},
    quota = #{quota}, entry_fee = #{entryFee}, description = #{description},
    status = #{status}
WHERE id = #{id}

mapper.select:
SELECT

FROM event e
WHERE e.id = #{id}

SELECT
FROM event e WHERE 1=1
AND e.name LIKE CONCAT('%', #{keyword}, '%')
AND e.status = #{status}
ORDER BY e.create_time DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM event e WHERE 1=1

    AND e.name LIKE CONCAT('%', #{keyword}, '%')


    AND e.status = #{status}
